import {
  transition,
  trigger,
  query,
  style,
  animate,
  group
} from '@angular/animations';



export const fadedAnimataion =
  trigger('routeAnimations', [
    transition('homePage => *', [
      query(':enter, :leave', style({ position: 'absolute', width: '100%', top: '50%' })),
      group([
        query(':enter', [
          style({ opacity: 0 }),
          animate('0.4s', style({ opacity: 1 }))
        ]),
        query(':leave', [
          style({ opacity: 0 }),
          animate('0.4s', style({ opacity: 0 }))
        ]),
      ])
    ]),
    transition('aboutPage => *', [
      query(':enter, :leave', style({ position: 'absolute', width: '100%', top: '50% '})),
      group([
        query(':enter', [
          style({ opacity: 0 }),
          animate('0.4s', style({ opacity: 1 }))
        ]),
        query(':leave', [
          style({ opacity: 0 }),
          animate('0.4s', style({ opacity: 0 }))
        ]),
      ])
    ]),

  ]);
